import { Component, OnDestroy } from '@angular/core';
import { Observable, Subject } from 'rxjs';
import { ThemeState, fromAppSelectors } from '../../store';
import { Store } from '@ngrx/store';
import { OverlayContainer } from '@angular/cdk/overlay';
import { takeUntil } from 'rxjs/operators';

@Component({
  selector: 'rg-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.scss']
})
export class AppComponent implements OnDestroy {

  public isMenuOpen: Observable<boolean>;
  public darkTheme: Observable<boolean>;
  private destroyed = new Subject<void>();

  constructor(private themeStore: Store<ThemeState>, private overlayContainer: OverlayContainer) {
    this.darkTheme = this.themeStore.select(fromAppSelectors.fromTheme.getDarkTheme);
    this.isMenuOpen = this.themeStore.select(fromAppSelectors.fromTheme.getMenuOpen);
    this.darkTheme.pipe(takeUntil(this.destroyed)).subscribe(isDark => this.onThemeChange(isDark));
  }

  public ngOnDestroy(): void {
    this.destroyed.next();
    this.destroyed.complete();
  }

  onThemeChange(isDark: boolean) {
    const overlayContainerClasses = this.overlayContainer.getContainerElement().classList;
    if (isDark) {
      overlayContainerClasses.add('alternate-theme');
    } else {
      overlayContainerClasses.remove('alternate-theme');
    }
  }

}
