import { Action } from '@ngrx/store';

export const TOGGLE_DARK_MODE = '[App] Toggle Dark Mode';
export const OPEN_CLOSE_MENU = '[App] Open or Close Menu';

export class ToggleDarkMode implements Action {
    readonly type = TOGGLE_DARK_MODE;
    constructor() { }
}

export class OpenCloseMenu implements Action {
    readonly type = OPEN_CLOSE_MENU;
    constructor(public open: boolean) { }
}

export type ThemeActions = ToggleDarkMode | OpenCloseMenu;
